const all = $input.all().map(i => i.json);
const passed = all.filter(r => r.status === 'PASS').length;
const failed = all.filter(r => r.status === 'FAIL').length;
const errors = all.filter(r => r.status === 'ERROR').length;
return [{ json: {
  results: all,
  summary: { total: all.length, passed, failed, errors, pass_rate: Math.round(passed/Math.max(all.length,1)*100)+'%', run_date: new Date().toISOString() }
} }];

const {results, summary} = $input.first().json;
const icon = s => s==='PASS'?'✅':s==='FAIL'?'❌':'⚠️';
const rows = results.map(r => {
  const fails = (r.failures||[]).map(f => '<li style="color:#dc2626;font-size:12px">'+f+'</li>').join('');
  return '<tr style="border-bottom:1px solid #f3f0ff">'
    +'<td style="padding:8px 4px;font-size:12px;font-weight:600;color:#6b7280">'+r.sid+'</td>'
    +'<td style="padding:8px;font-size:13px;color:#111827">'+r.name+'</td>'
    +'<td style="padding:8px;text-align:center">'+icon(r.status)+' '+r.status+'</td>'
    +'<td style="padding:8px;font-size:13px;color:#6b7280">'+(r.lead_score??'—')+'</td>'
    +'<td style="padding:8px;font-size:13px;color:#6b7280">'+(r.service||'—')+'</td>'
    +'<td style="padding:8px;font-size:12px;color:#6b7280">'+(r.summary||'—')+(fails?'<ul style="margin:4px 0;padding-left:14px">'+fails+'</ul>':'')+'</td>'
    +'</tr>';
}).join('');
const ok = summary.failed===0 && summary.errors===0;
const bar = ok ? '#6C63FF' : '#dc2626';
const pc = ok ? '#16a34a' : '#dc2626';
const subj = (ok ? '✅ All Passing' : '❌ '+summary.failed+' Failed, '+summary.errors+' Errors')+' — HVAC Scenario Report '+new Date(summary.run_date).toLocaleDateString();
const html = '<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f3f4f6;font-family:-apple-system,sans-serif">'
  +'<table width="100%" bgcolor="#f3f4f6"><tr><td align="center" style="padding:32px 16px">'
  +'<table style="max-width:680px;width:100%">'
  +'<tr><td bgcolor="'+bar+'" style="height:4px;border-radius:8px 8px 0 0;font-size:4px">&nbsp;</td></tr>'
  +'<tr><td bgcolor="#ffffff" style="border-radius:0 0 12px 12px;padding:28px 32px">'
  +'<p style="margin:0 0 4px;font-size:10px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:#6C63FF">Syntharra · Weekly Health Check</p>'
  +'<h1 style="margin:0 0 20px;font-size:22px;font-weight:700;color:#111827">HVAC Scenario Report</h1>'
  +'<table width="100%" style="margin-bottom:20px"><tr>'
  +'<td style="width:25%;padding-right:6px"><table width="100%" bgcolor="#f7f5ff" style="border-radius:8px"><tr><td style="padding:12px;text-align:center"><p style="margin:0 0 3px;font-size:10px;font-weight:600;text-transform:uppercase;color:#9ca3af">Pass Rate</p><p style="margin:0;font-size:22px;font-weight:800;color:'+pc+'">'+summary.pass_rate+'</p></td></tr></table></td>'
  +'<td style="width:25%;padding-right:6px"><table width="100%" bgcolor="#f7f5ff" style="border-radius:8px"><tr><td style="padding:12px;text-align:center"><p style="margin:0 0 3px;font-size:10px;font-weight:600;text-transform:uppercase;color:#9ca3af">Passed</p><p style="margin:0;font-size:22px;font-weight:800;color:#16a34a">'+summary.passed+'</p></td></tr></table></td>'
  +'<td style="width:25%;padding-right:6px"><table width="100%" bgcolor="#f7f5ff" style="border-radius:8px"><tr><td style="padding:12px;text-align:center"><p style="margin:0 0 3px;font-size:10px;font-weight:600;text-transform:uppercase;color:#9ca3af">Failed</p><p style="margin:0;font-size:22px;font-weight:800;color:'+(summary.failed>0?'#dc2626':'#9ca3af')+'">'+summary.failed+'</p></td></tr></table></td>'
  +'<td style="width:25%"><table width="100%" bgcolor="#f7f5ff" style="border-radius:8px"><tr><td style="padding:12px;text-align:center"><p style="margin:0 0 3px;font-size:10px;font-weight:600;text-transform:uppercase;color:#9ca3af">Total</p><p style="margin:0;font-size:22px;font-weight:800;color:#6C63FF">'+summary.total+'</p></td></tr></table></td>'
  +'</tr></table>'
  +'<table width="100%"><tr>'
  +'<th style="padding:6px 4px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">ID</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">Scenario</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:center;text-transform:uppercase">Result</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">Score</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">Service</th>'
  +'<th style="padding:6px 8px;font-size:10px;font-weight:600;color:#9ca3af;text-align:left;text-transform:uppercase">Notes</th>'
  +'</tr>'+rows+'</table>'
  +'</td></tr></table></td></tr></table></body></html>';
return [{ json: { html, subject: subj } }];

